import{_ as o,o as d,c as a,ae as l}from"./chunks/framework.C7FLYIpo.js";const p=JSON.parse('{"title":"인증 자격 증명 시맨틱","description":"인증 프로파일에 대한 표준 자격 증명 적격성 및 해결 시맨틱","frontmatter":{"title":"인증 자격 증명 시맨틱","description":"인증 프로파일에 대한 표준 자격 증명 적격성 및 해결 시맨틱"},"headers":[],"relativePath":"auth-credential-semantics.md","filePath":"auth-credential-semantics.md","lastUpdated":null}'),i={name:"auth-credential-semantics.md"};function c(t,e,r,s,n,u){return d(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="인증-자격-증명-시맨틱" tabindex="-1">인증 자격 증명 시맨틱 <a class="header-anchor" href="#인증-자격-증명-시맨틱" aria-label="Permalink to &quot;인증 자격 증명 시맨틱&quot;">​</a></h1><p>이 문서는 다음에서 사용되는 표준 자격 증명 적격성 및 해결 시맨틱을 정의합니다:</p><ul><li><code>resolveAuthProfileOrder</code></li><li><code>resolveApiKeyForProfile</code></li><li><code>models status --probe</code></li><li><code>doctor-auth</code></li></ul><p>목표는 선택 시점 동작과 런타임 동작을 일치시키는 것입니다.</p><h2 id="안정적인-프로브-이유-코드" tabindex="-1">안정적인 프로브 이유 코드 <a class="header-anchor" href="#안정적인-프로브-이유-코드" aria-label="Permalink to &quot;안정적인 프로브 이유 코드&quot;">​</a></h2><ul><li><code>ok</code></li><li><code>excluded_by_auth_order</code></li><li><code>missing_credential</code></li><li><code>invalid_expires</code></li><li><code>expired</code></li><li><code>unresolved_ref</code></li><li><code>no_model</code></li></ul><h2 id="토큰-자격-증명" tabindex="-1">토큰 자격 증명 <a class="header-anchor" href="#토큰-자격-증명" aria-label="Permalink to &quot;토큰 자격 증명&quot;">​</a></h2><p>토큰 자격 증명(<code>type: &quot;token&quot;</code>)은 인라인 <code>token</code> 및/또는 <code>tokenRef</code>를 지원합니다.</p><h3 id="적격성-규칙" tabindex="-1">적격성 규칙 <a class="header-anchor" href="#적격성-규칙" aria-label="Permalink to &quot;적격성 규칙&quot;">​</a></h3><ol><li><code>token</code>과 <code>tokenRef</code>가 모두 없는 경우 토큰 프로파일은 부적격합니다.</li><li><code>expires</code>는 선택 사항입니다.</li><li><code>expires</code>가 있는 경우 <code>0</code>보다 큰 유한 숫자여야 합니다.</li><li><code>expires</code>가 유효하지 않은 경우(<code>NaN</code>, <code>0</code>, 음수, 비유한, 또는 잘못된 타입), 프로파일은 <code>invalid_expires</code>로 부적격합니다.</li><li><code>expires</code>가 과거인 경우 프로파일은 <code>expired</code>로 부적격합니다.</li><li><code>tokenRef</code>는 <code>expires</code> 유효성 검사를 우회하지 않습니다.</li></ol><h3 id="해결-규칙" tabindex="-1">해결 규칙 <a class="header-anchor" href="#해결-규칙" aria-label="Permalink to &quot;해결 규칙&quot;">​</a></h3><ol><li>해결기 시맨틱은 <code>expires</code>에 대한 적격성 시맨틱과 일치합니다.</li><li>적격한 프로파일의 경우, 토큰 자료는 인라인 값 또는 <code>tokenRef</code>에서 해결될 수 있습니다.</li><li>해결 불가능한 ref는 <code>models status --probe</code> 출력에서 <code>unresolved_ref</code>를 생성합니다.</li></ol><h2 id="명시적-인증-순서-필터링" tabindex="-1">명시적 인증 순서 필터링 <a class="header-anchor" href="#명시적-인증-순서-필터링" aria-label="Permalink to &quot;명시적 인증 순서 필터링&quot;">​</a></h2><ul><li>프로바이더에 대해 <code>auth.order.&lt;provider&gt;</code> 또는 인증 저장소 순서 재정의가 설정된 경우, <code>models status --probe</code>는 해당 프로바이더의 해결된 인증 순서에 남아 있는 프로파일 id만 프로브합니다.</li><li>명시적 순서에서 제외된 해당 프로바이더의 저장된 프로파일은 나중에 자동으로 시도되지 않습니다. 프로브 출력은 <code>reasonCode: excluded_by_auth_order</code> 및 세부 사항 <code>Excluded by auth.order for this provider.</code>로 보고합니다.</li></ul><h2 id="프로브-대상-해결" tabindex="-1">프로브 대상 해결 <a class="header-anchor" href="#프로브-대상-해결" aria-label="Permalink to &quot;프로브 대상 해결&quot;">​</a></h2><ul><li>프로브 대상은 인증 프로파일, 환경 자격 증명, 또는 <code>models.json</code>에서 올 수 있습니다.</li><li>프로바이더에 자격 증명이 있지만 OpenClaw가 해당 프로바이더에 대해 프로브 가능한 모델 후보를 해결할 수 없는 경우, <code>models status --probe</code>는 <code>status: no_model</code> 및 <code>reasonCode: no_model</code>로 보고합니다.</li></ul><h2 id="oauth-secretref-정책-가드" tabindex="-1">OAuth SecretRef 정책 가드 <a class="header-anchor" href="#oauth-secretref-정책-가드" aria-label="Permalink to &quot;OAuth SecretRef 정책 가드&quot;">​</a></h2><ul><li>SecretRef 입력은 정적 자격 증명 전용입니다.</li><li>프로파일 자격 증명이 <code>type: &quot;oauth&quot;</code>인 경우, 해당 프로파일 자격 증명 자료에는 SecretRef 객체가 지원되지 않습니다.</li><li><code>auth.profiles.&lt;id&gt;.mode</code>가 <code>&quot;oauth&quot;</code>인 경우, 해당 프로파일에 대한 SecretRef 기반 <code>keyRef</code>/<code>tokenRef</code> 입력은 거부됩니다.</li><li>위반은 시작/재로드 인증 해결 경로에서 하드 실패입니다.</li></ul><h2 id="레거시-호환-메시징" tabindex="-1">레거시 호환 메시징 <a class="header-anchor" href="#레거시-호환-메시징" aria-label="Permalink to &quot;레거시 호환 메시징&quot;">​</a></h2><p>스크립트 호환성을 위해 프로브 오류는 이 첫 번째 줄을 변경 없이 유지합니다:</p><p><code>Auth profile credentials are missing or expired.</code></p><p>이후 줄에 사람이 읽기 쉬운 세부 사항과 안정적인 이유 코드가 추가될 수 있습니다.</p>',22)])])}const f=o(i,[["render",c]]);export{p as __pageData,f as default};
